SELECT * FROM monitor_alert_history

    AND monitor_type = #{monitorType}
    AND status = #{status}
    AND created_at >= #{startTime}
    AND created_at <= #{endTime}

ORDER BY created_at DESC
LIMIT #{offset}, #{pageSize}

